297→    private final Object stateLock = new Object();
298→    protected volatile State state = State.CREATED;
299→
300→    private boolean waitOnStates(final long waitMs, final State... targetStates) {
301→        final Set<State> targetStateSet = Set.of(targetStates);
302→        final long begin = time.milliseconds();
303→        synchronized (stateLock) {
304→            boolean interrupted = false;
305→            long elapsedMs = 0L;
306→            try {
307→                while (!targetStateSet.contains(state)) {
308→                    if (waitMs > elapsedMs) {
309→                        final long remainingMs = waitMs - elapsedMs;
310→                        try {
311→                            stateLock.wait(remainingMs);
312→                        } catch (final InterruptedException e) {
313→                            interrupted = true;
314→                        }
315→                    } else {
316→                        log.debug(
317→                            "Cannot transit to {} within {}ms",
318→                            Arrays.stream(targetStates).map(State::toString).collect(Collectors.joining(" or ")),
319→                            waitMs
320→                        );
321→                        return false;
322→                    }
323→                    elapsedMs = time.milliseconds() - begin;
324→                }
325→            } finally {
326→                // Make sure to restore the interruption status before returning.
327→                // We do not always own the current thread that executes this method, i.e., we do not know the
328→                // interruption policy of the thread. The least we can do is restore the interruption status before
329→                // the current thread exits this method.
330→                if (interrupted) {
331→                    Thread.currentThread().interrupt();
332→                }
333→            }
334→            return true;
335→        }
336→    }
337→
338→    /**
339→     * Sets the state
340→     * @param newState New state
341→     */
342→    private boolean setState(final State newState) {
343→        final State oldState;
344→
345→        synchronized (stateLock) {
346→            oldState = state;
347→
348→            if (state == State.PENDING_SHUTDOWN && newState != State.NOT_RUNNING) {
349→                // when the state is already in PENDING_SHUTDOWN, all other transitions than NOT_RUNNING (due to thread dying) will be
350→                // refused, but we do not throw exception here, to allow appropriate error handling
351→                return false;
352→            } else if (state == State.NOT_RUNNING && (newState == State.PENDING_SHUTDOWN || newState == State.NOT_RUNNING)) {
353→                // when the state is already in NOT_RUNNING, its transition to PENDING_SHUTDOWN or NOT_RUNNING (due to consecutive close calls)
354→                // will be refused, but we do not throw exception here, to allow idempotent close calls
355→                return false;
356→            } else if (state == State.REBALANCING && newState == State.REBALANCING) {
357→                // when the state is already in REBALANCING, it should not transit to REBALANCING again
358→                return false;
359→            } else if (state == State.ERROR && (newState == State.PENDING_ERROR || newState == State.ERROR || newState == State.PENDING_SHUTDOWN)) {
360→                // when the state is already in ERROR, its transition attempts to PENDING_SHUTDOWN, PENDING_ERROR or ERROR will
361→                // not throw an exception.
362→                return false;
363→            } else if (state == State.PENDING_ERROR && newState != State.ERROR) {
364→                // when the state is already in PENDING_ERROR, all other transitions than ERROR (due to thread dying) will be
365→                // refused, but we do not throw exception here, to allow appropriate error handling
366→                return false;
367→            } else if (!state.isValidTransition(newState)) {
368→                throw new IllegalStateException("Stream-client " + clientId + ": Unexpected state transition from " + oldState + " to " + newState);
369→            } else {
370→                log.info("State transition from {} to {}", oldState, newState);
371→            }
372→            state = newState;
373→            stateLock.notifyAll();
374→        }
375→
376→        // we need to call the user customized state listener outside the state lock to avoid potential deadlocks
377→        if (stateListener != null) {
378→            stateListener.onChange(newState, oldState);
379→        }
380→
381→        return true;
382→    }
