484→    private void replaceStreamThread(final Throwable throwable) {
485→        if (globalStreamThread != null && Thread.currentThread().getName().equals(globalStreamThread.getName())) {
486→            log.warn("The global thread cannot be replaced. Reverting to shutting down the client.");
487→            log.error("Encountered the following exception during processing " +
488→                    " The streams client is going to shut down now. ", throwable);
489→            closeToError();
490→        }
491→        final StreamThread deadThread = (StreamThread) Thread.currentThread();
492→        deadThread.shutdown(org.apache.kafka.streams.CloseOptions.GroupMembershipOperation.REMAIN_IN_GROUP);
493→        addStreamThread();
494→        if (throwable instanceof RuntimeException) {
495→            throw (RuntimeException) throwable;
496→        } else if (throwable instanceof Error) {
497→            throw (Error) throwable;
498→        } else {
499→            throw new RuntimeException("Unexpected checked exception caught in the uncaught exception handler", throwable);
500→        }
501→    }
502→
503→    private void handleStreamsUncaughtException(final Throwable throwable,
504→                                                final StreamsUncaughtExceptionHandler streamsUncaughtExceptionHandler,
505→                                                final boolean skipThreadReplacement) {
506→        final StreamsUncaughtExceptionHandler.StreamThreadExceptionResponse action = streamsUncaughtExceptionHandler.handle(throwable);
507→
508→        switch (action) {
509→            case REPLACE_THREAD:
510→                if (!skipThreadReplacement) {
511→                    log.error("Replacing thread in the streams uncaught exception handler", throwable);
512→                    replaceStreamThread(throwable);
513→                } else {
514→                    log.debug("Skipping thread replacement for recoverable error");
515→                }
516→                break;
517→            case SHUTDOWN_CLIENT:
518→                log.error(
519→                    "Encountered the following exception during processing and the registered exception handler " +
520→                        "opted to {}. The streams client is going to shut down now.",
521→                    action,
522→                    throwable
523→                );
524→                closeToError();
525→                break;
526→            case SHUTDOWN_APPLICATION:
527→                if (numLiveStreamThreads() == 1) {
528→                    log.warn("Attempt to shut down the application requires adding a thread to communicate the shutdown. No processing will be done on this thread");
529→                    addStreamThread();
530→                }
531→                if (throwable instanceof Error) {
532→                    log.error("This option requires running threads to shut down the application." +
533→                            "but the uncaught exception was an Error, which means this runtime is no " +
534→                            "longer in a well-defined state. Attempting to send the shutdown command anyway.", throwable);
535→                }
536→                if (Thread.currentThread().equals(globalStreamThread) && numLiveStreamThreads() == 0) {
537→                    log.error("Exception in global thread caused the application to attempt to shutdown." +
538→                            " This action will succeed only if there is at least one StreamThread running on this client." +
539→                            " Currently there are no running threads so will now close the client.");
540→                    closeToError();
541→                    break;
542→                }
543→                processStreamThread(StreamThread::sendShutdownRequest);
544→                log.error("Encountered the following exception during processing " +
545→                        "and sent shutdown request for the entire application.", throwable);
546→                break;
547→        }
548→    }
