585→    /**
586→     * Get read-only handle on global metrics registry, including streams client's own metrics plus
587→     * its embedded producer, consumer and admin clients' metrics.
588→     *
589→     * @return Map of all metrics.
590→     */
591→    public Map<MetricName, ? extends Metric> metrics() {
592→        final Map<MetricName, Metric> result = new LinkedHashMap<>();
593→        // producer and consumer clients are per-thread
594→        processStreamThread(thread -> {
595→            result.putAll(thread.producerMetrics());
596→            result.putAll(thread.consumerMetrics());
597→            // admin client is shared, so we can actually move it
598→            // to result.putAll(adminClient.metrics()).
599→            // we did it intentionally just for flexibility.
600→            result.putAll(thread.adminClientMetrics());
601→        });
602→        // global thread's consumer client
603→        if (globalStreamThread != null) {
604→            result.putAll(globalStreamThread.consumerMetrics());
605→        }
606→        // self streams metrics
607→        result.putAll(metrics.metrics());
608→        return Collections.unmodifiableMap(result);
609→    }
