321→    private void buildAndVerifyTopology(final InternalTopologyBuilder builder) {
322→        builder.rewriteTopology(config);
323→        builder.buildTopology();
324→
325→        final Set<String> allInputTopicsCopy = new HashSet<>(allInputTopics);
326→
327→        // As we go, check each topology for overlap in the set of input topics/patterns
328→        final int numInputTopics = allInputTopicsCopy.size();
329→        final List<String> inputTopics = builder.fullSourceTopicNames();
330→        final Collection<String> inputPatterns = builder.allSourcePatternStrings();
331→
332→        final Set<String> newInputTopics = new HashSet<>(inputTopics);
333→        newInputTopics.addAll(inputPatterns);
334→
335→        final int numNewInputTopics = newInputTopics.size();
336→        allInputTopicsCopy.addAll(newInputTopics);
337→
338→        if (allInputTopicsCopy.size() != numInputTopics + numNewInputTopics) {
339→            inputTopics.retainAll(allInputTopicsCopy);
340→            inputPatterns.retainAll(allInputTopicsCopy);
341→            log.error("Tried to add the NamedTopology {} but it had overlap with other input topics {} or patterns {}",
342→                      builder.topologyName(), inputTopics, inputPatterns);
343→            throw new TopologyException("Named Topologies may not subscribe to the same input topics or patterns");
344→        }
345→
346→        final ProcessorTopology globalTopology = builder.buildGlobalStateTopology();
347→        if (globalTopology != null) {
348→            if (builder.topologyName() != null) {
349→                throw new IllegalStateException("Global state stores are not supported with Named Topologies");
350→            } else if (this.globalTopology != null) {
351→                throw new TopologyException("Topology builder had global state, but global topology has already been set");
352→            } else {
353→                this.globalTopology = globalTopology;
354→                globalStateStores.putAll(builder.globalStateStores());
355→            }
356→        }
357→        allInputTopics.addAll(newInputTopics);
358→    }
