 55→/**
 56→ * {@code StreamsProducer} manages the producers within a Kafka Streams application.
 57→ * <p>
 58→ * If EOS is enabled, it is responsible to init and begin transactions if necessary.
 59→ * It also tracks the transaction status, ie, if a transaction is in-fight.
 60→ * <p>
 61→ * For non-EOS, the user should not call transaction related methods.
 62→ */
 63→public class StreamsProducer {
 64→    private final Logger log;
 65→    private final String logPrefix;
 66→
 67→    private final ProcessingMode processingMode;
 68→    private final Time time;
 69→
 70→    private Producer<byte[], byte[]> producer;
 71→    private boolean transactionInFlight = false;
 72→    private boolean transactionInitialized = false;
 73→    private double oldProducerTotalBlockedTime = 0;
 74→    // we have a single `StreamsProducer` per thread, and thus a single `sendException` instance,
 75→    // which we share across all tasks, ie, all `RecordCollectorImpl`
 76→    private final AtomicReference<KafkaException> sendException = new AtomicReference<>(null);
 77→
 78→    public StreamsProducer(final Producer<byte[], byte[]> producer,
 79→                           final ProcessingMode processingMode,
 80→                           final Time time,
 81→                           final LogContext logContext) {
 82→        this.producer = Objects.requireNonNull(producer, "producer cannot be null");
 83→        this.processingMode = Objects.requireNonNull(processingMode, "processingMode cannot be null");
 84→        this.time = Objects.requireNonNull(time, "time cannot be null");
 85→        log = Objects.requireNonNull(logContext, "logContext cannot be null").logger(getClass());
 86→        logPrefix = logContext.logPrefix().trim();
 87→    }
 88→
 89→    private String formatException(final String message) {
 90→        return message + " [" + logPrefix + "]";
 91→    }
 92→
 93→    boolean eosEnabled() {
 94→        return processingMode == EXACTLY_ONCE_V2;
 95→    }
 96→
 97→    boolean transactionInFlight() {
 98→        return transactionInFlight;
 99→    }
100→
101→    /**
102→     * @throws IllegalStateException if EOS is disabled
103→     */
104→    void initTransaction() {
105→        if (!eosEnabled()) {
106→            throw new IllegalStateException(formatException("Exactly-once is not enabled"));
107→        }
108→        if (!transactionInitialized) {
109→            // initialize transactions if eos is turned on, which will block if the previous transaction has not
110→            // completed yet; do not start the first transaction until the topology has been initialized later
111→            try {
112→                producer.initTransactions();
113→                transactionInitialized = true;
114→            } catch (final TimeoutException timeoutException) {
115→                log.warn(
116→                    "Timeout exception caught trying to initialize transactions. " +
117→                        "The broker is either slow or in bad state (like not having enough replicas) in " +
118→                        "responding to the request, or the connection to broker was interrupted sending " +
119→                        "the request or receiving the response. " +
120→                        "Will retry initializing the task in the next loop. " +
121→                        "Consider overwriting {} to a larger value to avoid timeout errors",
122→                    ProducerConfig.MAX_BLOCK_MS_CONFIG
123→                );
124→
125→                // re-throw to trigger `task.timeout.ms`
126→                throw timeoutException;
127→            } catch (final KafkaException exception) {
128→                throw new StreamsException(
129→                    formatException("Error encountered trying to initialize transactions"),
130→                    exception
131→                );
132→            }
133→        }
134→    }
