150→    private double getMetricValue(final Map<MetricName, ? extends Metric> metrics,
151→                                  final String name) {
152→        final List<MetricName> found = metrics.keySet().stream()
153→            .filter(n -> n.name().equals(name))
154→            .collect(Collectors.toList());
155→        if (found.isEmpty()) {
156→            return 0.0;
157→        }
158→        if (found.size() > 1) {
159→            final String err = String.format(
160→                "found %d values for metric %s. total blocked time computation may be incorrect",
161→                found.size(),
162→                name
163→            );
164→            log.error(err);
165→            throw new IllegalStateException(err);
166→        }
167→        return (Double) metrics.get(found.get(0)).metricValue();
168→    }
169→
170→    private double totalBlockedTime(final Producer<?, ?> producer) {
171→        return getMetricValue(producer.metrics(), "bufferpool-wait-time-ns-total")
172→            + getMetricValue(producer.metrics(), "flush-time-ns-total")
173→            + getMetricValue(producer.metrics(), "txn-init-time-ns-total")
174→            + getMetricValue(producer.metrics(), "txn-begin-time-ns-total")
175→            + getMetricValue(producer.metrics(), "txn-send-offsets-time-ns-total")
176→            + getMetricValue(producer.metrics(), "txn-commit-time-ns-total")
177→            + getMetricValue(producer.metrics(), "txn-abort-time-ns-total")
178→            + getMetricValue(producer.metrics(), "metadata-wait-time-ns-total");
179→    }
180→
181→    public double totalBlockedTime() {
182→        return oldProducerTotalBlockedTime + totalBlockedTime(producer);
183→    }
