329→    public Map<TaskId, RuntimeException> drainUncaughtExceptions() {
330→        final Map<TaskId, RuntimeException> returnValue = returnWithTasksLocked(() -> {
331→            final Map<TaskId, RuntimeException> result = new HashMap<>(uncaughtExceptions);
332→            uncaughtExceptions.clear();
333→            return result;
334→        });
335→
336→        if (!returnValue.isEmpty()) {
337→            log.debug("Drained {} uncaught exceptions", returnValue.size());
338→        }
339→
340→        return returnValue;
341→    }
